import React from "react";
import { NavLink } from "react-router-dom";
import "./HeroSection.css"; // იგივე სტილი

export default function StartTest() {
  return (
    <section className="hero">
      <div className="hero-content">

        <div className="hero-logo">
          <img src="/logo.png" alt="MBTI Logo" />
        </div>

        <h1 className="hero-title">MBTI ტესტი</h1>

        <p className="hero-description">
          უპასუხე კითხვებს გულწრფელად და გაიგე შენი ფსიქოტიპი,
          ძლიერი მხარეები და გადაწყვეტილების სტილი
        </p>

        <NavLink to="/test/questions" className="hero-button">
          დაწყება
        </NavLink>

      </div>
    </section>
  );
}
